&lt;ul&gt;
	&lt;li data-end=&quot;230&quot; data-start=&quot;132&quot;&gt;
	&lt;p data-end=&quot;230&quot; data-start=&quot;134&quot;&gt;&lt;strong data-end=&quot;154&quot; data-start=&quot;134&quot;&gt;India ranks 99th&lt;/strong&gt; out of &lt;strong data-end=&quot;179&quot; data-start=&quot;162&quot;&gt;167 countries&lt;/strong&gt; in the &lt;strong data-end=&quot;205&quot; data-start=&quot;187&quot;&gt;2025 SDG Index&lt;/strong&gt;, with a &lt;strong data-end=&quot;229&quot; data-start=&quot;214&quot;&gt;score of 67&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;394&quot; data-start=&quot;231&quot;&gt;
	&lt;p data-end=&quot;394&quot; data-start=&quot;233&quot;&gt;This is the &lt;strong data-end=&quot;259&quot; data-start=&quot;245&quot;&gt;first time&lt;/strong&gt; India entered the &lt;strong data-end=&quot;289&quot; data-start=&quot;278&quot;&gt;top 100&lt;/strong&gt; in the &lt;strong data-end=&quot;337&quot; data-start=&quot;297&quot;&gt;Sustainable Development Report (SDR)&lt;/strong&gt; by the &lt;strong data-end=&quot;393&quot; data-start=&quot;345&quot;&gt;UN Sustainable Development Solutions Network&lt;/strong&gt;.&lt;/p&gt;
