		&lt;/li&gt;
		&lt;li data-end=&quot;528&quot; data-start=&quot;504&quot;&gt;
		&lt;p data-end=&quot;528&quot; data-start=&quot;506&quot;&gt;&lt;strong data-end=&quot;516&quot; data-start=&quot;506&quot;&gt;Nepal:&lt;/strong&gt; 85th (68.6)&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;561&quot; data-start=&quot;531&quot;&gt;
		&lt;p data-end=&quot;561&quot; data-start=&quot;533&quot;&gt;&lt;strong data-end=&quot;548&quot; data-start=&quot;533&quot;&gt;Bangladesh:&lt;/strong&gt; 114th (63.9)&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;590&quot; data-start=&quot;564&quot;&gt;
		&lt;p data-end=&quot;590&quot; data-start=&quot;566&quot;&gt;&lt;strong data-end=&quot;579&quot; data-start=&quot;566&quot;&gt;Pakistan:&lt;/strong&gt; 140th (57)&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;664&quot; data-start=&quot;591&quot;&gt;
	&lt;p data-end=&quot;617&quot; data-start=&quot;593&quot;&gt;&lt;strong data-end=&quot;617&quot; data-start=&quot;593&quot;&gt;Maritime neighbours:&lt;/strong&gt;&lt;/p&gt;

	&lt;ul data-end=&quot;664&quot; data-start=&quot;620&quot;&gt;
		&lt;li data-end=&quot;640&quot; data-start=&quot;620&quot;&gt;
		&lt;p data-end=&quot;640&quot; data-start=&quot;622&quot;&gt;&lt;strong data-end=&quot;635&quot; data-start=&quot;622&quot;&gt;Maldives:&lt;/strong&gt; 53rd&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;664&quot; data-start=&quot;643&quot;&gt;
		&lt;p data-end=&quot;664&quot; data-start=&quot;645&quot;&gt;&lt;strong data-end=&quot;659&quot; data-start=&quot;645&quot;&gt;Sri Lanka:&lt;/strong&gt; 93rd&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;710&quot; data-start=&quot;665&quot;&gt;
	&lt;p data-end=&quot;710&quot; data-start=&quot;667&quot;&gt;&lt;strong data-end=&quot;684&quot; data-start=&quot;667&quot;&gt;US ranks 44th&lt;/strong&gt; with a score of &lt;strong data-end=&quot;709&quot; data-start=&quot;701&quot;&gt;75.2&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;862&quot; data-start=&quot;711&quot;&gt;
	&lt;p data-end=&quot;741&quot; data-start=&quot;713&quot;&gt;&lt;strong data-end=&quot;739&quot; data-start=&quot;713&quot;&gt;Top global performers:&lt;/strong&gt;&lt;/p&gt;

	&lt;ul data-end=&quot;862&quot; data-start=&quot;744&quot;&gt;
		&lt;li data-end=&quot;764&quot; data-start=&quot;744&quot;&gt;
		&lt;p data-end=&quot;764&quot; data-start=&quot;746&quot;&gt;&lt;strong data-end=&quot;754&quot; data-start=&quot;746&quot;&gt;1st:&lt;/strong&gt; Finland&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;786&quot; data-start=&quot;767&quot;&gt;
		&lt;p data-end=&quot;786&quot; data-start=&quot;769&quot;&gt;&lt;strong data-end=&quot;777&quot; data-start=&quot;769&quot;&gt;2nd:&lt;/strong&gt; Sweden&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;809&quot; data-start=&quot;789&quot;&gt;
		&lt;p data-end=&quot;809&quot; data-start=&quot;791&quot;&gt;&lt;strong data-end=&quot;799&quot; data-start=&quot;791&quot;&gt;3rd:&lt;/strong&gt; Denmark&lt;/p&gt;
		&lt;/li&gt;
		&lt;li data-end=&quot;862&quot; data-start=&quot;812&quot;&gt;
		&lt;p data-end=&quot;862&quot; data-start=&quot;814&quot;&gt;19 of the &lt;strong data-end=&quot;834&quot; data-start=&quot;824&quot;&gt;top 20&lt;/strong&gt; are &lt;strong data-end=&quot;861&quot; data-start=&quot;839&quot;&gt;European countries&lt;/strong&gt;.&lt;/p&gt;
