	&lt;/li&gt;
	&lt;li data-end=&quot;949&quot; data-start=&quot;863&quot;&gt;
	&lt;p data-end=&quot;893&quot; data-start=&quot;865&quot;&gt;&lt;strong data-end=&quot;891&quot; data-start=&quot;865&quot;&gt;SDG Index score range:&lt;/strong&gt;&lt;/p&gt;

	&lt;ul data-end=&quot;949&quot; data-start=&quot;896&quot;&gt;
		&lt;li data-end=&quot;949&quot; data-start=&quot;896&quot;&gt;
		&lt;p data-end=&quot;949&quot; data-start=&quot;898&quot;&gt;&lt;strong data-end=&quot;917&quot; data-start=&quot;898&quot;&gt;0 = no progress&lt;/strong&gt;, &lt;strong data-end=&quot;949&quot; data-start=&quot;919&quot;&gt;100 = all 17 SDGs achieved&lt;/strong&gt;&lt;/p&gt;
		&lt;/li&gt;
	&lt;/ul&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1046&quot; data-start=&quot;950&quot;&gt;
	&lt;p data-end=&quot;1046&quot; data-start=&quot;952&quot;&gt;&lt;strong data-end=&quot;980&quot; data-start=&quot;952&quot;&gt;Global progress stalled:&lt;/strong&gt; Only &lt;strong data-end=&quot;1008&quot; data-start=&quot;986&quot;&gt;17% of SDG targets&lt;/strong&gt; projected to be achieved by &lt;strong data-end=&quot;1045&quot; data-start=&quot;1037&quot;&gt;2030&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;1122&quot; data-start=&quot;1047&quot;&gt;
	&lt;p data-end=&quot;1122&quot; data-start=&quot;1049&quot;&gt;SDGs adopted in &lt;strong data-end=&quot;1073&quot; data-start=&quot;1065&quot;&gt;2015&lt;/strong&gt; to ensure &lt;strong data-end=&quot;1109&quot; data-start=&quot;1084&quot;&gt;no one is left behind&lt;/strong&gt; by &lt;strong data-end=&quot;1121&quot; data-start=&quot;1113&quot;&gt;2030&lt;/strong&gt;.&lt;/p&gt;
	&lt;/li&gt;
&lt;/ul&gt;<br><br>&lt;p&gt;सही उत्तर &lt;u&gt;&lt;strong&gt;99&lt;/strong&gt;&lt;/u&gt; है।&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/in_news.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;In News&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;भारत पहली बार संयुक्त राष्ट्र की वैश्विक सतत विकास लक्ष्य (SDG) रैंकिंग में शीर्ष 100 में शामिल हुआ है।&lt;/li&gt;
&lt;/ul&gt;

&lt;p&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;span style=&quot;display: flex;gap: 6px;align-items: center;&quot;&gt;&lt;img height=&quot;26px&quot; src=&quot;//cdn.testbook.com/resources/lms_creative_elements/key-point-image.png&quot; width=&quot;26px&quot; /&gt;&lt;strong&gt;&lt;span style=&quot;vertical-align: middle;font-size: 21px;&quot;&gt;&lt;u&gt;Key Points&lt;/u&gt;&lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li data-end=&quot;230&quot; data-start=&quot;132&quot;&gt;
	&lt;p data-end=&quot;230&quot; data-start=&quot;134&quot;&gt;&lt;strong data-end=&quot;154&quot; data-start=&quot;134&quot;&gt;भारत का रैंक 99वाँ&lt;/strong&gt; है, जो &lt;strong data-end=&quot;179&quot; data-start=&quot;162&quot;&gt;167 देशों&lt;/strong&gt; में से &lt;strong data-end=&quot;205&quot; data-start=&quot;187&quot;&gt;2025 SDG सूचकांक&lt;/strong&gt; में है, जिसमें &lt;strong data-end=&quot;229&quot; data-start=&quot;214&quot;&gt;67 का स्कोर&lt;/strong&gt; है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;394&quot; data-start=&quot;231&quot;&gt;
	&lt;p data-end=&quot;394&quot; data-start=&quot;233&quot;&gt;यह &lt;strong data-end=&quot;259&quot; data-start=&quot;245&quot;&gt;पहली बार&lt;/strong&gt; है जब भारत &lt;strong data-end=&quot;289&quot; data-start=&quot;278&quot;&gt;शीर्ष 100&lt;/strong&gt; में &lt;strong data-end=&quot;337&quot; data-start=&quot;297&quot;&gt;सतत विकास रिपोर्ट (SDR)&lt;/strong&gt; में &lt;strong data-end=&quot;393&quot; data-start=&quot;345&quot;&gt;संयुक्त राष्ट्र सतत विकास समाधान नेटवर्क&lt;/strong&gt; द्वारा शामिल हुआ है।&lt;/p&gt;
	&lt;/li&gt;
	&lt;li data-end=&quot;447&quot; data-start=&quot;395&quot;&gt;
